/**
 * API Route Tests: GET /api/render/start
 * Testa o endpoint de render start (src/app/api/render/start/route.ts)
 *
 * Nota: Testa apenas o GET que não requer auth.
 * POST requer auth + Supabase → integration test.
 */

// Mock rate limit to always allow
jest.mock('@/lib/rate-limit', () => ({
  applyRateLimit: jest.fn().mockResolvedValue(null),
  checkRateLimit: jest.fn().mockResolvedValue({
    allowed: true,
    retryAfterSec: 0,
    remaining: 99,
    limit: 100,
    resetAtMs: Date.now() + 60_000,
    source: 'memory',
  }),
  globalRateLimiter: {
    check: jest.fn().mockReturnValue({ success: true, remaining: 99, limit: 100 }),
    checkAsync: jest.fn().mockResolvedValue({ allowed: true }),
    configure: jest.fn(),
    limit: 100,
    windowMs: 60_000,
  },
}));

// Mock logger
jest.mock('@/lib/logger', () => ({
  logger: {
    debug: jest.fn(),
    info: jest.fn(),
    warn: jest.fn(),
    error: jest.fn(),
  },
}));

import { GET } from '@/app/api/render/start/route';
import { NextRequest } from 'next/server';

function createNextRequest(url: string): NextRequest {
  return new NextRequest(new URL(url, 'http://localhost:3000'));
}

describe('GET /api/render/start', () => {
  it('should return success with available actions', async () => {
    const req = createNextRequest('/api/render/start');
    const response = await GET(req);
    const body = await response.json();

    expect(response.status).toBe(200);
    expect(body.success).toBe(true);
    expect(body.available_actions).toContain('video-pipeline');
    expect(body.available_actions).toContain('video-test');
  });

  it('should handle action=video-pipeline', async () => {
    const req = createNextRequest('/api/render/start?action=video-pipeline');
    const response = await GET(req);
    const body = await response.json();

    expect(response.status).toBe(200);
    expect(body.success).toBe(true);
    expect(body.endpoint).toContain('video-pipeline');
  });

  it('should handle action=video-test', async () => {
    const req = createNextRequest('/api/render/start?action=video-test');
    const response = await GET(req);
    const body = await response.json();

    expect(response.status).toBe(200);
    expect(body.success).toBe(true);
    expect(body.status).toBe('operational');
    expect(body.pipeline_status).toBe('ready');
  });

  it('should return 405 for action=create-video-job via GET', async () => {
    const req = createNextRequest('/api/render/start?action=create-video-job');
    const response = await GET(req);
    const body = await response.json();

    expect(response.status).toBe(405);
    expect(body.code).toBe('METHOD_NOT_ALLOWED');
    expect(body.documentation).toBeDefined();
    expect(body.documentation.method).toBe('POST');
  });
});
